import 'dart:io';

import 'package:forui/src/create/codec.dart';

import '../args/command.dart';
import '../args/prompts.dart';
import '../configuration.dart';
import '../commands/theme/theme.dart';
import 'typography.dart';
import 'icons.dart';

const _themeHeader = '''
import 'package:forui/forui.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

part 'colors.dart';
part 'typography.dart';
part 'style.dart';
part 'icons.dart';

/// Generated by Forui CLI.
///
/// Modify the generated function bodies to create your own custom style.
/// Then, call the modified function and pass it to [FTheme].
///
/// You can also generate styles to be used in the generated [FThemeData] using:
/// ```shell
/// dart forui style create [styles]
/// ```
///
/// See:
/// * https://forui.dev/docs/guides/customizing-themes for customizing themes.
/// * https://forui.dev/docs/guides/customizing-widget-styles for customizing individual widget styles.''';

String _colorsHeader(String themeFileName) =>
    '''
part of '$themeFileName';

/// Generated by Forui CLI.
///
/// Color tokens and theme extensions for the generated theme.''';

String _typographyHeader(String themeFileName) =>
    '''
part of '$themeFileName';

/// Generated by Forui CLI.
///
/// Typography tokens for the generated theme.''';

String _styleHeader(String themeFileName) =>
    '''
part of '$themeFileName';

// ignore_for_file: avoid_redundant_argument_values

/// Generated by Forui CLI.
///
/// Style tokens and theme extensions for the generated theme.''';

String _iconsHeader(String themeFileName) =>
    '''
part of '$themeFileName';

/// Generated by Forui CLI.
///
/// Icon tokens for the generated theme.''';

Future<void> create(
  Configuration configuration,
  Preset preset, {
  required bool input,
  required bool force,
  required String output,
}) async {
  await installTypography(preset, configuration.root, directory: configuration.fonts, force: force);
  await installIcons(preset, configuration.root);

  final iconImportStatement = preset.icon.import;

  final separator = Platform.pathSeparator;
  final themePath =
      '${configuration.root.path}$separator${output.endsWith('.dart') ? output : '$output${separator}theme.dart'}';
  final themeDir = File(themePath).parent.path;
  final themeFileName = themePath.split(separator).last;
  final colorsPath = '$themeDir${separator}colors.dart';
  final typographyPath = '$themeDir${separator}typography.dart';
  final stylePath = '$themeDir${separator}style.dart';
  final iconsPath = '$themeDir${separator}icons.dart';

  if (!force) {
    for (final path in [themePath, colorsPath, typographyPath, stylePath, iconsPath]) {
      final file = File(path);
      if (file.existsSync()) {
        confirm(file, input: input);
      }
    }
  }

  stdout
    ..writeln('${emoji ? '⏳' : '[Waiting]'} Creating themes...')
    ..writeln();

  final header = iconImportStatement == null
      ? _themeHeader
      : _themeHeader.replaceFirst(
          "import 'package:flutter/services.dart';",
          "import 'package:flutter/services.dart';\n$iconImportStatement",
        );

  final themeBuffer = StringBuffer('$header\n')
    ..writeln(Theme.neutral.source)
    ..writeln();
  final colorsBuffer = StringBuffer('${_colorsHeader(themeFileName)}\n')
    ..writeln(colors(preset))
    ..writeln();
  final typographyBuffer = StringBuffer('${_typographyHeader(themeFileName)}\n')
    ..writeln(generateTypography(preset))
    ..writeln();
  final styleBuffer = StringBuffer('${_styleHeader(themeFileName)}\n')
    ..writeln(style(preset))
    ..writeln();
  final iconsBuffer = StringBuffer('${_iconsHeader(themeFileName)}\n')
    ..writeln(generateIcons(preset))
    ..writeln();

  File(themePath)
    ..createSync(recursive: true)
    ..writeAsStringSync(formatter.format(themeBuffer.toString()));
  File(colorsPath)
    ..createSync(recursive: true)
    ..writeAsStringSync(formatter.format(colorsBuffer.toString()));
  File(typographyPath)
    ..createSync(recursive: true)
    ..writeAsStringSync(formatter.format(typographyBuffer.toString()));
  File(stylePath)
    ..createSync(recursive: true)
    ..writeAsStringSync(formatter.format(styleBuffer.toString()));
  File(iconsPath)
    ..createSync(recursive: true)
    ..writeAsStringSync(formatter.format(iconsBuffer.toString()));

  stdout
    ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(themePath)}')
    ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(colorsPath)}')
    ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(typographyPath)}')
    ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(stylePath)}')
    ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(iconsPath)}')
    ..writeln()
    ..writeln('See https://forui.dev/docs/guides/customizing-themes for how to use the generated theme.');
}

String colors(Preset preset) {
  final light = _colors(preset.base.light, preset.primary?.light, light: true);
  final dark = _colors(preset.base.dark, preset.primary?.dark, light: false);
  final stub = _after(Theme.neutral.colors, '/// Provides convenient access to theme extensions on [FColors].');

  return 'final FColors lightColors = $light;\n\nfinal FColors darkColors = $dark;\n\n$stub';
}

String _after(String source, String marker) => source.substring(source.indexOf(marker));

String _colors(BaseColors base, PrimaryColors? primary, {required bool light}) =>
    '''
FColors(
  brightness: .${light ? 'light' : 'dark'},
  systemOverlayStyle: .${light ? 'dark' : 'light'},
  barrier: ${_color(base.barrier)},
  background: ${_color(base.background)},
  foreground: ${_color(base.foreground)},
  primary: ${_color(primary?.primary ?? base.primary)},
  primaryForeground: ${_color(primary?.primaryForeground ?? base.primaryForeground)},
  secondary: ${_color(base.secondary)},
  secondaryForeground: ${_color(base.secondaryForeground)},
  muted: ${_color(base.muted)},
  mutedForeground: ${_color(base.mutedForeground)},
  destructive: ${_color(base.destructive)},
  destructiveForeground: ${_color(base.destructiveForeground)},
  error: ${_color(base.error)},
  errorForeground: ${_color(base.errorForeground)},
  card: ${_color(base.card)},
  border: ${_color(base.border)},
  extensions: const [AppColors()],
)''';

String _color(int color) => 'Color(0x${color.toRadixString(16).padLeft(8, '0').toUpperCase()})';

String style(Preset preset) {
  if (preset.radius == Radius.medium) {
    return Theme.neutral.style;
  }

  final radius = preset.radius.radius;
  return Theme.neutral.style.replaceAll('FBorderRadius()', '''
FBorderRadius(
  xs2: ${_radius(radius.xs2)},
  xs: ${_radius(radius.xs)},
  sm: ${_radius(radius.sm)},
  md: ${_radius(radius.md)},
  lg: ${_radius(radius.lg)},
  xl: ${_radius(radius.xl)},
  xl2: ${_radius(radius.xl2)},
  xl3: ${_radius(radius.xl3)},
  pill: ${_radius(radius.pill)},
)''');
}

String _radius(double value) => value == 0 ? '.zero' : '.all(.circular($value))';
